<template>
  <div id="question">
  	<h2>提出话题</h2>
  	<form v-if='!submitted'>
      <div class="card">
        <label>标题</label>
        <input type="text" name="" placeholder="标题" v-model='question.title' id="title">
        <p v-if="question.title == ''">*标题不能为空</p>
      </div>

  		<div class="card">
        <label>话题描述</label>
        <textarea  placeholder="详细描述" v-model='question.describe'></textarea>
      </div>

  		<div class="card">
        <label>分类</label>
        <div id="checkboxes">
          <label>人文</label>
          <input type="checkbox" name="" value="人文" v-model='question.categories'>
          <label>历史</label>
          <input type="checkbox" name="" value="历史" v-model='question.categories'>
          <label>政治</label>
          <input type="checkbox" name="" value="政治" v-model='question.categories'>
          <label>娱乐</label>
          <input type="checkbox" name="" value="娱乐" v-model='question.categories'>
          <label>军事</label>
          <input type="checkbox" name="" value="军事" v-model='question.categories'>
          <label>动漫</label>
          <input type="checkbox" name="" value="动漫" v-model='question.categories'>
          <label>科技</label>
          <input type="checkbox" name="" value="科技" v-model='question.categories'>
          <label>体育</label>
          <input type="checkbox" name="" value="体育" v-model='question.categories'>
          <label>其他</label>
          <input type="checkbox" name="" value="其他" v-model='question.categories'>
        </div>
      </div>
      
  		<button v-on:click.prevent = 'post()'>提交</button>
  	</form>
    <h3 v-if='submitted'>问题提交成功</h3>
  </div>
</template>

<script>
import axios from 'axios'
export default {
  name: 'question',
  data () {
    return {
     question:{
       	title:'',
       	describe:'',
        categories:[],
        author:''
     },
     submitted:false,
     empty:true
    }
  },
  created(){
    axios.get('https://wd6653727231vwclvk.wilddogio.com/condition.json')
      .then((data) =>{
        this.question.author = data.data.name;
        console.log(this.question.author);
      })
  }, 
  methods:{
  	post:function(){
      if (this.question.title == '') {
        alert('请填写标题');
      }else {
        axios.post('https://wd6653727231vwclvk.wilddogio.com/posts.json', this.question)
        .then((data) =>{
          this.submitted = true;
        });
      }
  	}
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
#question{
  width: 60%;
  margin: 70px auto;
}
h2{
  text-align: center;
  color: rgb(31, 78, 121);
}
.card{
  background: #fff;
  margin-top: 10px;
  width: 100%;
  box-shadow: 2px 2px 2px #ccc;
  box-sizing: border-box;
  padding: 25px 10%;
}
label{
  display: inline-block;
  margin-bottom: 10px;
  color: rgb(31, 78, 121);
  font-weight: bold;
  font-size: 18px;
}
input[type = 'text'],textarea{
  display: block;
  margin: 10px 0 5px 0;
  width: 100%;
  font-size: 16px;
}
textarea{
  height: 150px;
}
#checkboxes label{
  margin: 0px;
  color: #000;
  margin-top: 10px;
  font-weight: normal;
  font-size: 16px;
}
#checkboxes input{
  margin-right: 10px;
}
button{
  width: 100%;
  height: 40px;
  font-size: 16px;
  margin: 10px 0; 
  background: rgb(31, 78, 121);
  color: #fff;
  border: none;
  border-radius: 5px;
}
p{
  margin: 0;
  font-size: 10px;
  color: red;
}
</style>



