<template>
  <div id="login">
  	<div v-if='!submitted'>
  		<h2>欢迎回来</h2>
	  	<img src="../assets/header.jpeg">
	  	<form>
	  		<label>账号</label>
	  		<input type="text" name="" placeholder="请输入账号" ref='id'>
	  		<p>{{jId}}</p>
	  		<label>密码</label>
	  		<input type="password" name="" placeholder="请输入密码" ref='psd'>
	  		<p>{{jPsd}}</p>
	  		<button @click.prevent='login'>登录</button>
	  	</form>
	  	<!-- <router-link to='/register'>没有账号？立即注册！</router-link> -->
	  	<span @click='reg'>没有账号？立即注册！</span>
  	</div>
  	<h3 v-if='submitted'>登录成功</h3>
  </div>
</template>

<script>
import axios from 'axios'
export default {
  inject:['reload'],
  name: 'login',
  data () {
    return {
     	curUser:{
     		name:'',
     		login:false,
     		reg:false
     	},
	    jId:'',
	    jPsd:'',
	    submitted: false
    }
  },
  created(){
  	axios.patch('https://wd6653727231vwclvk.wilddogio.com/condition.json',{reg:this.curUser.reg})
  },
  methods:{
  	login:function(){
  		axios.get('https://wd6653727231vwclvk.wilddogio.com/users.json')
	  	.then((data)=>{
		  for(let key in data.data){
		  	if (this.$refs.id.value == data.data[key].name) {
		  		if (this.$refs.psd.value == data.data[key].password) {
		  			this.jPsd = '';
		  			this.jId = '';
		  			this.curUser.name=this.$refs.id.value;
		  			this.curUser.login=true;
		  			axios.patch('https://wd6653727231vwclvk.wilddogio.com/condition.json',{name:this.curUser.name,login:this.curUser.login})
		  			.then(()=>{
		  				this.submitted=true;
	  					location.reload();
		  			})
		  			break;
		  		}else{
		  			this.jPsd = '密码错误';
		  			this.jId = '';
		  			break;
		  		}
		  	}else{
		  		this.jPsd = '';
		  		this.jId = '用户不存在';
		  		continue;
		  	}
		  }
	  	});
  	},
  	reg:function(){
  		this.curUser.reg = true;
  		axios.patch('https://wd6653727231vwclvk.wilddogio.com/condition.json',{reg:this.curUser.reg})
  		.then(()=>{
			location.reload();
		})
  	}
  }
}
</script>
<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
#login{
	width: 25%;
	margin: 150px auto 0;
	box-sizing: border-box;
}
h2{
	text-align: center;
	background: #fff;
	height: 60px;
	line-height: 60px;
	box-shadow: 2px 2px 2px #ccc;
	border-radius: 10px 10px 0 0;
	color: rgb(31, 78, 121);
}
form{
	background: #fff;
	padding: 15px 30px;
	box-shadow: 2px 2px 2px #ccc;
	border-radius: 0 0 10px 10px;
}
label{
	display: inline-block;
	margin: 10px 10px 0 0;
	color: rgb(31, 78, 121);
	font-weight: bold;
}
img{
	width: 64px;
	height: 64px;
	border-radius: 50%;
	display: block;
	margin: 20px auto;
	box-shadow: 0px 5px 5px #444;
}
input{
	width: 80%;
	height: 24px;
	margin-top: 10px;
	border: none;
	background: url(../assets/bg.png);
	box-shadow: 2px 2px 2px #ccc inset;
}
p{
	margin: 0;
	font-size: 10px;
	color: red;
}
button{
	width: 100%;
	height: 40px;
	font-size: 16px;
	margin: 20px 0; 
	background: rgb(31, 78, 121);
	color: #fff;
	border: none;
	border-radius: 5px;
}
span{
	display: block;
	text-decoration: none;
	text-align: right;
	color: rgb(31, 78, 121);
	font-size: 14px;
	margin-top: 10px;
	cursor: pointer;
}
h3{
	color: rgb(31, 78, 121);
	text-align: center;
}
</style>


