<template>
  <div id="home">
  	<h2>Enjoy yourselves here!</h2>
    <input type="text" name="" placeholder="搜索..." v-model='search'>
    <div id="ques">
      <div v-for='question in filteredQuestions' :key='question.title' class="singleQues" @mouseenter='move($event)' @mouseleave='back($event)'>
        <div class="cir"></div>
        <router-link v-bind:to="'/question/' + question.id">
          <h3>{{question.title}}</h3>
        </router-link>
        <p>提问人：{{question.author}}</p>
        <article>{{question.describe}}</article>
      </div>
    </div>
    
    <div id='info' ref='info' :class="isFixed ? 'fix' :''">
      <div id="personal" ref='personal'>
        <div class="cir" id="rc"></div>
        <!-- <router-link to='/personal'><p>个人信息</p></router-link> -->
        <p>个人信息</p>
        <p>我的回答</p>
        <p>我顶的回答</p>
        <p>我踩的回答</p>
      </div>
      <div id="show">
        <ul ref='pic'>
          <li><img src="../assets/1.jpeg"></li><li><img src="../assets/2.jpeg"></li><li><img src="../assets/3.jpeg"></li><li><img src="../assets/1.jpeg"></li>
        </ul>
      </div>
    </div>
  </div>
</template>

<script>
import axios from 'axios'
export default {
  name: 'home',
  data () {
    return {
      questions:[],
      search:'',
      isFixed:false
    }
  },
  created(){
    axios.get('https://wd6653727231vwclvk.wilddogio.com/posts.json')
    .then(function(data){
      return data.data;
    })
    .then((data) =>{
      var questionsArray = [];
      for(let key in data){
        data[key].id = key;
        questionsArray.push(data[key]);
      }
      this.questions = questionsArray;
    })
  },
  mounted(){
    window.addEventListener('scroll', this.handleScroll);
    this.change();
  },
  computed:{
    filteredQuestions: function(){
      return this.questions.filter((question => {
        return question.title.match(this.search)
      }))
    }
  },
  destroyed () {
    window.removeEventListener('scroll', this.handleScroll)
  },
  methods:{
    move:function(event){
      let cur = event.currentTarget;
      cur.style.left = '-30px';
      cur.style.transitionDuration = '0.5s';
    },
    back:function(event){
      let cur = event.currentTarget;
      cur.style.left = '0px';
      cur.style.transitionDuration = '0.5s';
    },
    handleScroll:function(){
      let scrollTop = document.documentElement.scrollTop;
      if (scrollTop >= 100) {
        this.$refs.info.style.top = scrollTop - '100' + 'px';
      }else {
        this.$refs.info.style.top = '0';
      }
    },
    change:function(){
      var e = this.$refs.pic;
      var posi = 0;
      var run = setInterval(function(){
        posi -=250;
        if (posi == -750) {
          posi=0;
        }
        e.style.left= posi + 'px';
        e.style.transitionDuration = '1s';
        
        console.log(e.style.left);
      }, 3000)
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
#home{
  width: 75%;
  margin: 70px auto;
  padding-top: 20px;
}
h2{
  margin-top: 20px;
  color: #888;
}
input{
  width: 300px;
  height: 30px;
  font-size: 16px;
  margin-bottom: 20px;
}
#ques{
  display: inline-block;
  width: 70%;
  margin: 0;
  padding: 0;
  border: none;
}
.singleQues{
  width: 100%;
  margin: 5px 0;
  background: #fff;
  border-radius: 5px;
  padding: 10px;
  box-shadow: 2px 2px 2px #ccc;
  box-sizing: border-box;
  padding: 0 40px 15px;
  position: relative;
  left: 0;
}
h3{
  margin: 10px;
  color: rgb(31, 78, 121);
}
#ques p{
  margin: 10px;
  color: #888;
}
article{
  margin: 10px;
  font-size: 14px;
}
a{
  text-decoration: none;
}
.ask{
  display: block;
  text-decoration: none;
  color: #fff;
  background: rgb(31, 78, 121);
  width: 84px;
  height: 24px;
  line-height: 24px;
  text-align: center;
  border-radius: 12px;
  margin: 10px 0;
}
.cir{
  width: 20px;
  height: 20px;
  border-radius: 10px;
  border: none;
  background: url(../assets/bg.png);
  box-shadow: 2px 2px 2px #ccc inset;
  position: relative;
  top: 15px;
  left: -20px;
  margin: 0;
  padding: 0;
}
#info{
  width: 250px;
  display: inline-block;
  position: relative;
  margin: 0;
  padding: 0;
  vertical-align: top;
}
#personal{
  width: 250px;
  height: 300px;
  border-radius: 5px;
  display: inline-block; 
  vertical-align: top;
  margin: 5px 15px;
  background: #fff;
  box-shadow: 2px 2px 2px #ccc;
  /*padding: 10px 40px;*/
  box-sizing: border-box;
  position: relative;
}
#rc{
  position: relative;
  left: 20px;
  top: 20px;
  margin-bottom: 30px;
}
#personal p{
  color: #888;
  text-align: center;
  margin: 0;
  height: 48px;
  line-height: 48px;
}
#personal p:hover{
  color: #fff;
  /*font-weight: bold;*/
  cursor: pointer;
  background: rgb(31, 78, 121);
  border-radius: 5px;
}
.fix{
  position: fixed;
  top: 72px;
}
img{
  width: 250px;
  padding: 0;
}
#show{
  width: 250px;
  height: 167px;
  overflow: hidden;
  position: relative;
  margin: 25px 15px;
  border-radius: 5px;
  box-shadow: 2px 2px 2px #ccc;
}
ul{
  width: 1000px;
  margin: 0;
  padding: 0;
  position: absolute;
  left: 0;
}
li{
  list-style: none;
  margin: 0;
  padding: 0;
  display: inline-block;
}
</style>



