<template>
  <div id="bar">
  	<ul>
		<li id="more" @mouseenter='more()' @mouseleave='less()' @click='change()' ref='more'>导</li>
		<div id="bord">
			<div ref='exp' id="exp">
				<li id="ask" ref='ask'><router-link v-bind:to="'/ask'">去</router-link></li>
				<li id="ask" ref='ask'><router-link v-bind:to="'/ask'">提</router-link></li>
				<li id="ask" ref='ask'><router-link v-bind:to="'/ask'">问</router-link></li>
				<li id="backTop" ref='backTop' @click='backTop()'>顶</li>
			</div>
		</div>
		
	</ul>
  </div>
</template>

<script>
import axios from 'axios'
export default {
  name: 'bar',
  data () {
    return {
     open:false
    }
  },
  methods:{
  	more:function(){
  		console.log(111);
  		this.$refs.more.style.transform = 'rotate(360deg)';
  		this.$refs.more.style.transitionDuration = '1s';
  	},
  	less:function(){
  		console.log(222);
  		this.$refs.more.style.transform = 'rotate(0deg)';
  		this.$refs.more.style.transitionDuration = '1s';
  	},
  	change:function(){
  		if (this.open) {
  			this.$refs.exp.style.top = '-128px';
  			this.$refs.exp.style.transitionDuration = '1s';
  			this.open = false;
  		}else {
  			this.$refs.exp.style.top = '0px';
  			this.$refs.exp.style.transitionDuration = '1s';
  			this.open = true;
  		}
  	},
  	backTop:function(){
  		let speed = 40;
		let back = setInterval(function(){
			document.documentElement.scrollTop -= speed;
			if (document.documentElement.scrollTop == 0) {
				clearInterval(back);
			}
		}, 20);
  	}
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
ul{
	margin: 0;
	padding: 0;
	position: fixed;
	right: 10px;
	top: 40%;
}
li{
	border-radius: 50%;
	width: 36px;
	height: 36px;
	border: none;
	background: rgb(31, 78, 121);
	text-align: center;
	color: #fff;
	font-size: 16px;
	line-height: 36px;
	margin-top: 6px;
	cursor: pointer;
	list-style-type: none;
}
a{
	text-decoration: none;
	color: #fff;
}
#more{
	z-index: 10;
	position: relative;
}
#bord{
	position: relative;
	overflow: hidden;
	top: -16px;
	padding-top: 18px;
}
#exp{
	position: relative;
	top: -128px;
}
</style>



