<template>
  <div id="register">
  	<div v-if='!submitted'>
  		<h2>欢迎注册</h2>
	  	<img src="../assets/header.jpeg">
	  	<form>
	  		<label>用户名</label>
	  		<input type="text" name="" placeholder="请输入账号" v-model='newUser.name' ref="user">
	  		<p>{{juser}}</p>
	  		<label>密码</label>
	  		<input type="password" name="" placeholder="请输入密码" v-model='newUser.password' ref="psd">
	  		<p>{{jpsd}}</p>
	  		<label>确认密码</label>
	  		<input type="password" name="" placeholder="请再次输入密码" ref="repsd">
	  		<p>{{jrepsd}}</p>
	  		<button @click.prevent='register'>注册</button>
	  	</form>
	  	<!-- <router-link to='/login'>去登陆</router-link> -->
	  	<span @click='log'>去登陆</span>
  	</div>
  	<h3 v-if='submitted'>恭喜你注册成功！</h3>
  </div>
</template>

<script>
import axios from 'axios'
export default {
  name: 'register',
  data () {
    return {
     newUser:{
     	name:'',
     	password:''
     },
	 juser:'输入用户名',
	 jpsd:'输入密码',
	 jrepsd:'重复密码',
	 submitted:false
    }
  },
  watch:{
  		newUser: function(){
			if (this.$refs.user.value.length >= 3 && this.$refs.user.value.length <= 10) {
		  		this.juser = '';
		  		console.log(123);
		  	}else {
		  		this.juser = '长度在3~10位'
		  	}
	  	}
  	
  	
  	
  },
  methods:{
  	register:function(){
  		if (this.$refs.user.value.length >= 3 && this.$refs.user.value.length <= 10) {
	  		this.juser = '正确';
	  	}else {
	  		this.juser = '长度在3~10位';
	  	};
	  	if (this.$refs.psd.value.length >= 3 && this.$refs.psd.value.length <= 10) {
	  		this.jpsd = '正确';
	  	}else {
	  		this.jpsd = '长度在3~10位'
	  	};
	  	if (this.$refs.psd.value == this.$refs.repsd.value) {
	  		this.jrepsd = '正确';
	  	}else {
	  		this.jrepsd = '长度在3~10位'
	  	};
		if (this.juser == this.jpsd && this.juser == this.jrepsd && this.jrepsd == this.jpsd) {
			axios.post('https://wd6653727231vwclvk.wilddogio.com/users.json',this.newUser)
			.then((data) =>{
	           this.submitted = true;
	        });
		}
  	},
  	log:function(){
  		axios.patch('https://wd6653727231vwclvk.wilddogio.com/condition.json',{reg:false})
  		.then(()=>{
			location.reload();
		})
  	}
  }
}
</script>
<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
#register{
	width: 25%;
	margin: 120px auto 0;
}
h2{
	text-align: center;
	background: #fff;
	height: 60px;
	line-height: 60px;
	box-shadow: 2px 2px 2px #ccc;
	border-radius: 10px 10px 0 0;
	color: rgb(31, 78, 121);
}
form{
	background: #fff;
	padding: 15px 30px;
	box-shadow: 2px 2px 2px #ccc;
	border-radius: 0 0 10px 10px;
}
label{
	display: inline-block;
	margin: 10px 10px 0 0;
	color: rgb(31, 78, 121);
	font-weight: bold;
}
img{
	width: 64px;
	height: 64px;
	border-radius: 50%;
	display: block;
	margin: 20px auto;
	box-shadow: 0px 5px 5px #444;
}
input{
	width: 70%;
	height: 24px;
	margin-top: 10px;
	float: right;
	border: none;
	background: url(../assets/bg.png);
	box-shadow: 2px 2px 2px #ccc inset;
}
p{
	margin: 0;
	font-size: 10px;
	color: red;
}
button{
	width: 100%;
	height: 40px;
	font-size: 16px;
	margin: 20px 0; 
	background: rgb(31, 78, 121);
	color: #fff;
	border: none;
	border-radius: 5px;
}
span{
	display: block;
	text-decoration: none;
	text-align: right;
	font-size: 14px;
	color: rgb(31, 78, 121);
	margin-top: 10px;
	cursor: pointer;
}
h3{
	text-align: center;
	color: rgb(31, 78, 121);
	margin-top: 250px;
}
</style>



